const a="IsiNgisi",e="Isiphi isizinda sedatha ongathanda ukusisebenzisa?",i="Awudingi ukusetha noma yini. Lesi sithombe se-Docker sishumekiwe futhi sakulungisela i-MariaDB ngokuzenzakalelayo. I-Pong izoxhuma kule database ngesokhethi le-Unix.",s="Xhuma kusizindalwazi sangaphandle se-MariaDB. Udinga ukusetha imininingwane yokuxhumana yesizindalwazi.",t="Ifayela lesizindalwazi elilula, elinconyelwe ukuthunyelwa kwezinga elincane. Ngaphambi kwe-v2.0.0, i-Pong yasebenzisa i-SQLite njengesizindalwazi esizenzakalelayo.",n="Ukusetha isizindalwazi. Kungase kuthathe isikhashana, sicela ubekezele.",u="Igama lesizindalwazi",l="Nika amandla i-SSL/TLS",z="Nika amandla ukusebenzisa uxhumano olubethelwe kusizindalwazi sakho. Iyadingeka kuzigcinilwazi eziningi zamafu.",o="Isitifiketi se-CA",b="Namathisela I-CA Cert ngefomethi ye-PEM ukuze uyisebenzise nezitifiketi ezizisayinele. Shiya kungenalutho uma isizindalwazi sakho sisebenzisa isitifiketi esisayinwe yi-CA yomphakathi.",k={languageName:a,setupDatabaseChooseDatabase:e,setupDatabaseEmbeddedMariaDB:i,setupDatabaseMariaDB:s,setupDatabaseSQLite:t,settingUpDatabaseMSG:n,dbName:u,enableSSL:l,mariadbUseSSLHelptext:z,mariadbCaCertificateLabel:o,mariadbCaCertificateHelptext:b};export{u as dbName,k as default,l as enableSSL,a as languageName,b as mariadbCaCertificateHelptext,o as mariadbCaCertificateLabel,z as mariadbUseSSLHelptext,n as settingUpDatabaseMSG,e as setupDatabaseChooseDatabase,i as setupDatabaseEmbeddedMariaDB,s as setupDatabaseMariaDB,t as setupDatabaseSQLite};
